    checkAlertThresholds(name, responseTime) {
        const thresholds = this.config.monitoring.alertThresholds;
        const connectionInfo = this.connections.get(name);
        
        if (!connectionInfo) return;
        
        const metrics = connectionInfo.metrics;
        const failureRate = metrics.failedRequests / metrics.totalRequests;
        
        // Check failure rate
        if (failureRate > thresholds.failureRate) {
            this.sendAlert(name, 'high_failure_rate', {
                failureRate: (failureRate * 100).toFixed(2) + '%',
                threshold: (thresholds.failureRate * 100) + '%'
            });
        }
        
        // Check response time
        if (responseTime > thresholds.responseTime) {
            this.sendAlert(name, 'slow_response', {
                responseTime: responseTime + 'ms',
                threshold: thresholds.responseTime + 'ms'
            });
        }
    }

