    runConnectionLoop() {
        // Keep the connection manager running
        const loopInterval = setInterval(() => {
            if (!this.isRunning) {
                clearInterval(loopInterval);
                return;
            }
            
            // Check for any disconnected connections that need reconnection
            this.checkDisconnectedConnections();
            
        }, 10000); // Check every 10 seconds
    }

    checkDisconnectedConnections() {
        for (const [name, connectionInfo] of this.connections) {
            if (connectionInfo.config.enabled && connectionInfo.status === 'disconnected') {
                // Try to reconnect
                this.attemptReconnection(name);
            }
        }
    }

    async getConnection(name) {
        const pool = this.connectionPools.get(name);
        
        if (pool) {
            // Try to get a connection from the pool
            for (const connection of pool.connections) {
                if (!connection.inUse) {
                    connection.inUse = true;
                    connection.lastUsed = Date.now();
                    return connection;
                }
            }
            
            // Create a new connection if under max limit
            if (pool.connections.length < pool.maxConnections) {
                const newConnection = await this.createPooledConnection(name);
                if (newConnection) {
                    newConnection.inUse = true;
                    newConnection.lastUsed = Date.now();
                    return newConnection;
                }
            }
            
            // Add to waiting queue
            return new Promise((resolve) => {
                pool.waitingQueue.push(resolve);
            });
        }
        
        // Fallback to direct connection
        const connectionInfo = this.connections.get(name);
        if (connectionInfo && connectionInfo.status === 'connected') {
            return this.createConnection(connectionInfo.currentEndpoint, connectionInfo.config);
        }
        
        throw new Error(`No available connection for ${name}`);
    }

    releaseConnection(name, connection) {
        const pool = this.connectionPools.get(name);
        
        if (pool && connection) {
            connection.inUse = false;
            connection.lastUsed = Date.now();
            
            // Check if anyone is waiting for a connection
            if (pool.waitingQueue.length > 0) {
                const resolve = pool.waitingQueue.shift();
                connection.inUse = true;
                connection.lastUsed = Date.now();
                resolve(connection);
            }
        }
    }

